14	const isAlive = (cell: Cell, cells: Cell[]): boolean =>
15	  cells.some(([x, y]) => x === cell[0] && y === cell[1]);
16	
17	const deadNeighbors = (cells: Cell[]): Cell[] => {
18	  const result: Cell[] = [];
19	  for (const [x, y] of cells) {
20	    for (let dx = -1; dx <= 1; dx++) {
21	      for (let dy = -1; dy <= 1; dy++) {
22	        const candidate: Cell = [x + dx, y + dy];
23	        if (!isAlive(candidate, cells) && !isAlive(candidate, result)) {
24	          result.push(candidate);
25	        }
26	      }
27	    }
