32	export const nextGeneration = (cells: Cell[]): Cell[] => {
33	  const survivors = cells.filter((cell) =>
34	    survives(countLiveNeighbors(cell, cells))
35	  );
36	  const births = deadNeighbors(cells).filter(
37	    (cell) => countLiveNeighbors(cell, cells) === 3
38	  );
39	  return [...survivors, ...births];
40	};
